import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        char[] buffer = new char[10];

        // Use Math.min to limit the number of characters copied to prevent buffer overflow
        int length = Math.min(name.length(), buffer.length);

        // Copy characters from name to buffer
        for (int i = 0; i < length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Hello, " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
